fix.code:
package requirements {
    requirement def Shape {
        doc /* The system shall be a perfect cube of 1 m on each edge. */
    }

    requirement def Material {
        doc /* The system shall be made of 2024 Aluminium. */
    }

    requirement def Weight {
        doc /* The system shall weigh no more than 1 kg. */
    }

    requirement def ConflictResolution {
        doc /* Priority and resolution for the Shape, Material, and Weight requirements shall be as follows: (1) Shape and Material are mandatory and take precedence; (2) Weight is a secondary objective that shall be met if feasible within the mandated geometry and material; (3) if analysis shows the 1 kg limit cannot be achieved with a perfect 1 m cube made of 2024 Aluminium, the conflict shall be formally escalated for stakeholder rewrite of the Weight requirement rather than changing Shape or Material without approval. */
    }

    requirement resolution : ConflictResolution;
    refine requirement resolution to Shape;
    refine requirement resolution to Material;
    refine requirement resolution to Weight;

    comment conflictRationale {
        doc /* Rationale: explicit precedence is required because the combination of geometry, material, and mass may be infeasible. This model records the approved trade: preserve geometry and material, treat mass as the adjustable requirement, and escalate if infeasible. */
    }
}

